  1	import { type FC, useMemo } from 'react';
  2	import SectionHeading from 'src/components/headers/SectionHeading';
  3	import useGetDeleteAndEditAccessReview from 'src/modules/Providers/hooks/useGetDeleteAndEditAccessReview';
  4	import useProviderInventory from 'src/modules/Providers/hooks/useProviderInventory';
  5	import { ModalHOC } from 'src/modules/Providers/modals/ModalHOC/ModalHOC';
  6	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
  7	import { useForkliftTranslation } from 'src/utils/i18n';
  8	
  9	import {
 10	  type CnoConfig,
 11	  type OpenShiftNetworkAttachmentDefinition,
 12	  ProviderModel,
 13	} from '@kubev2v/types';
 14	import { Button, ButtonVariant, PageSection, PageSectionVariants } from '@patternfly/react-core';
 15	import { Table, TableVariant, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 16	import { DEFAULT_NETWORK, EMPTY_MSG } from '@utils/constants';
 17	
 18	import { useProvider } from '../../hooks/useProvider';
 19	import type { ProviderDetailsPageProps } from '../../utils/types';
 20	
 21	import DefaultNetworkLabel from './components/DefaultNetworkLabel';
 22	import EditProviderDefaultTransferNetwork from './components/EditProviderDefaultTransferNetwork';
 23	
 24	const ProviderNetworksTabPage: FC<ProviderDetailsPageProps> = ({ name, namespace }) => {
 25	  const { t } = useForkliftTranslation();
 26	  const { provider } = useProvider(name, namespace);
 27	
 28	  const { showModal } = useModal();
 29	
 30	  const {
 31	    error,
 32	    inventory: networks,
 33	    loading,
 34	  } = useProviderInventory<OpenShiftNetworkAttachmentDefinition[]>({
 35	    provider,
 36	    subPath: 'networkattachmentdefinitions?detail=4',
 37	  });
 38	
 39	  const permissions = useGetDeleteAndEditAccessReview({ model: ProviderModel, namespace });
 40	
 41	  const defaultNetworkName = useMemo(
 42	    () => provider?.metadata?.annotations?.['forklift.konveyor.io/defaultTransferNetwork'],
 43	    [provider?.metadata?.annotations],
 44	  );
 45	
 46	  const networksDataList = useMemo(
 47	    () =>
 48	      !loading && !error && Array.isArray(networks)
 49	        ? networks?.map((network) => {
 50	            const config = network?.object?.spec?.config;
 51	            return {
 52	              config: JSON.parse(config?.length ? config : '{}') as CnoConfig,
 53	              isDefault: `${network?.namespace}/${network?.name}` === defaultNetworkName,
 54	              name: network?.name,
 55	              namespace: network?.namespace,
 56	            };
 57	          })
 58	        : [],
 59	    [defaultNetworkName, error, loading, networks],
 60	  );
 61	
 62	  const onClick = () => {
 63	    showModal(
 64	      <EditProviderDefaultTransferNetwork
 65	        resource={provider}
 66	        defaultNetworkName={defaultNetworkName}
 67	      />,
 68	    );
 69	  };
 70	
 71	  return (
 72	    <ModalHOC>
 73	      <div>
 74	        <PageSection variant={PageSectionVariants.light}>
 75	          <SectionHeading text={t('NetworkAttachmentDefinitions')} />
 76	          {permissions.canPatch && (
 77	            <div>
 78	              <Button key="editTransferNetwork" variant={ButtonVariant.secondary} onClick={onClick}>
 79	                {t('Set provider default transfer network')}
 80	              </Button>
 81	            </div>
 82	          )}
 83	          <Table variant={TableVariant.compact}>
 84	            <Thead>
 85	              <Tr>
 86	                <Th width={30}>{t('Name')}</Th>
 87	                <Th width={30}>{t('Project')}</Th>
 88	                <Th width={30}>{t('Type')}</Th>
 89	              </Tr>
 90	            </Thead>
 91	            <Tbody>
 92	              <Tr key={DEFAULT_NETWORK}>
 93	                <Td>
 94	                  {DEFAULT_NETWORK} {!defaultNetworkName && <DefaultNetworkLabel />}
 95	                </Td>
 96	                <Td>{EMPTY_MSG}</Td>
 97	                <Td modifier="truncate">{DEFAULT_NETWORK}</Td>
 98	              </Tr>
 99	              {networksDataList?.map((data) => (
100	                <Tr key={data.name}>
101	                  <Td>
102	                    {data.name} {data.isDefault && <DefaultNetworkLabel />}
103	                  </Td>
104	                  <Td modifier="truncate"> {data?.namespace || EMPTY_MSG}</Td>
105	                  <Td modifier="truncate">{data?.config?.type || EMPTY_MSG}</Td>
106	                </Tr>
107	              ))}
108	            </Tbody>
109	          </Table>
110	        </PageSection>
111	      </div>
112	    </ModalHOC>
113	  );
114	};
115	
116	export default ProviderNetworksTabPage;

